        public boolean doTargetedAggregation(SailPointContext context, String nativeId, String appName, Attributes aggArgs) {
        boolean isAggOK = true;

        try {
        Application app = context.getObjectByName(Application.class, appName);
        Connector connector = sailpoint.connector.ConnectorFactory.getConnector(app, null);

        if (aggArgs == null || aggArgs.isEmpty()) {
        aggArgs = new Attributes();
        // by default we'll force a full agg and skip deletes
        aggArgs.put("noOptimizeReaggregation", "true");
        aggArgs.put("checkDeleted", "false");
        }

        ResourceObject rObj = connector.getObject("account", nativeId, null);
        if (null == rObj) {
        return false;
        }

        Aggregator agg = new Aggregator(context, aggArgs);
        TaskResult taskResult = agg.aggregate(app, rObj);

        if (taskResult == null) {
        isAggOK = false;
        } else {
        isAggOK = true;
        }
        } catch (Exception e) {
        isAggOK = false;
        }

        return isAggOK;
        }

        public void writeToFile(String appName, HashMap writeParams){
        if(Util.isNotNullOrEmpty(appName) && null!=writeParams && !writeParams.isEmpty()){
        Application application = context.getObjectByName(Application.class,appName);
        if(null!=application){
        String fileName = application.getAttributeValue("file");
        if(Util.isNotNullOrEmpty(fileName)){
        // open file in read-write mode
        RandomAccessFile randomAccessFile = new RandomAccessFile(new File(fileName), "rw");
        try {
        // get channel
        FileChannel channel = randomAccessFile.getChannel();

        // get lock
        FileLock tryLock = channel.lock();

        String data = "\n";
        String userName = writeParams.get("Username");
        String firstName = ((null == writeParams.get("Firstname")) ? "" : writeParams.get("Firstname"));
        String lastName =((null == writeParams.get("Lastname")) ? "" : writeParams.get("Lastname"));
        String employeeNumber = ((null == writeParams.get("EmployeeNumber")) ? "" : writeParams.get("EmployeeNumber"));
        String emailAddress = ((null == writeParams.get("EmailAddress")) ? "" : writeParams.get("EmailAddress"));
        String department = ((null == writeParams.get("Department")) ? "" : writeParams.get("Department"));
        String role = ((null == writeParams.get("Role")) ? "" : writeParams.get("Role"));

        String data="\n"+userName+","+firstName+","+lastName+","+employeeNumber+","+emailAddress+","+department+","+role;

        // write to end of file
        randomAccessFile.seek(randomAccessFile.length());
        randomAccessFile.write(data.getBytes());

        // release lock
        tryLock.release();

        // close file
        randomAccessFile.close();
        } catch (IOException e) {
        //TODO
        }
        }
        }
        }    
        }

        public String getRequesterCommnets(String identityRequestId, SailPointContext context) {
        logger.debug("Entering getRequesterCommnets");
        String comment = "";
        Map map = new HashMap();
        try {
        IdentityRequest identityRequestObj = context.getObjectByName(IdentityRequest.class, identityRequestId);
        if (identityRequestObj != null) {
        if (identityRequestObj.getItems() != null && !identityRequestObj.getItems().isEmpty()) {
        List <IdentityRequestItem> itemsList = identityRequestObj.getItems();
        for (IdentityRequestItem item: itemsList) {
        if (Util.isNotNullOrEmpty(item.getRequesterComments()) && Util.nullSafeCaseInsensitiveEq("IdentityIQ for ServiceNow Service Desk", item.getProvisioningEngine())) {

        map.put(item.getValue(), item.getRequesterComments());
        }
        }
        }
        //context.decache(identityRequestObj);
        }
        } catch (Exception ex) {
        logger.error("Exception in getRequesterCommnets " + ex.getMessage());
        }
        if (!Util.isEmpty(map)) {
        Collection values = map.values();
        if (!Util.isEmpty(values)) {
        List valueList = (new ArrayList(values));
        Util.removeDuplicates(valueList);
        comment = valueList.toString().substring(1, valueList.toString().length() - 1);
        }

        }
        logger.debug("Exiting getRequesterCommnets");
        return comment;
        }


        public String findAssignmentFromBundle(ManagedAttribute eachEntitlement, String identityRequestId, SailPointContext context) {
        logger.debug("Entering findAssignmentFromBundle");
        String result = "";
        String snowAssignmentGroup = "snowAssignmentGroup";

        String roleName = "";
        List <Application> inputAppList = new ArrayList();
        List <Profile> profileList = new ArrayList();
        boolean breakFlag = false;
        try {
        if (Util.isNotNullOrEmpty(identityRequestId) && eachEntitlement != null && Util.isNotNullOrEmpty(eachEntitlement.getAttribute()) &&
        Util.isNotNullOrEmpty(eachEntitlement.getValue()) && eachEntitlement.getApplication() != null) {
        inputAppList.add(eachEntitlement.getApplication());
        //get identity requestid obj
        IdentityRequest identityRequestObj = context.getObjectByName(IdentityRequest.class, identityRequestId);
        if (identityRequestObj != null) {
        if (identityRequestObj.getItems() != null && !identityRequestObj.getItems().isEmpty()) {
        List <IdentityRequestItem> itemsList = identityRequestObj.getItems();
        for (IdentityRequestItem item: itemsList) {
        if (breakFlag) {
        break;
        }
        if ("IIQ".equalsIgnoreCase(item.getApplication())) {
        roleName = "";
        if (item.getValue() instanceof String) {
        roleName = item.getValue().toString();
        } else if (item.getValue() instanceof List) {
        if (!((List) item.getValue()).isEmpty()) {
        roleName = ((List) item.getValue()).get(0).toString();
        }
        }
        // get role obj
        if (Util.isNotNullOrEmpty(roleName)) {
        Bundle bundle = context.getObjectByName(Bundle.class, roleName);
        if (bundle != null && bundle.getAttribute(snowAssignmentGroup) != null) {
        profileList = null;
        profileList = bundle.getProfilesForApplications(inputAppList);
        if (profileList != null && !profileList.isEmpty()) {
        for (Profile profile: profileList) {
        if (breakFlag) {
        break;
        }
        for (Filter filter: profile.getConstraints()) {
        if (Util.isNotNullOrEmpty(filter.getExpression())) {
        if (filter.getExpression().contains(eachEntitlement.getAttribute()) && filter.getExpression().contains(eachEntitlement.getValue())) {
        // get the assignment details and break
        result = (String) bundle.getAttribute(snowAssignmentGroup);
        breakFlag = true;
        }
        }
        }
        }
        }
        //context.decache(bundle);
        }
        }
        }
        }
        }
        //context.decache(identityRequestObj);
        }
        }
        } catch (Exception ex) {
        logger.error("Exception in findAssignmentFromBundle " + ex.getMessage());
        }
        logger.debug("Exiting findAssignmentFromBundle");
        return result;
        }

        public Map addPropertyInPlan(ManagedAttribute managedAttr) {
        Set setValue = new HashSet();
        setValue.add("approvalType");
        setValue.add("ascBusinessApplication");
        setValue.add("snowAssignmentGroup");
        setValue.add("snowAssignmentGroupName");
        setValue.add("sysDescriptions");

        Map attributeMap = new HashMap();
        if (null != managedAttr && null != managedAttr.getAttributes() && null != managedAttr.getAttributes().getMap()) {
        attributeMap = managedAttr.getAttributes().getMap();
        if (null != attributeMap && null != attributeMap.keySet()) {
        attributeMap.keySet().removeAll(setValue);
        }
        }
        return attributeMap;
        }



        void addAssignmentGroupInPlan(ProvisioningPlan plan, SailPointContext context, String reqName) {
        logger.debug("Starting addAssignmentGroupInPlan");
        String assignmentGroup = null;
        String businessApplication = null;
        boolean isAccReqAdded = false;

        if (plan != void && plan != null) {
        List accountRequests = plan.getAccountRequests();
        List splitAccountRequests = new ArrayList();
        if (!Util.isEmpty(accountRequests)) {
        for (AccountRequest request: accountRequests) {
        applicationName = request.getApplicationName();
        List attributeRequests = request.getAttributeRequests();
        isAccReqAdded = false;

        if (!Util.isEmpty(attributeRequests)) {
        for (AttributeRequest attrRequest: attributeRequests) {
        assignmentGroup = null;
        businessApplication = null;
        Map propertyMap = new HashMap();
        Map accReqAttrMap = new HashMap();
        Attributes propertyAttr = new Attributes();
        String attrName = attrRequest.getName();
        Object attrValue = attrRequest.getValue();
        Filter appFilter = Filter.eq("application.name", applicationName);
        Filter attributeFilter = Filter.eq("attribute", attrName);
        if (attrValue instanceof String && Util.isNotNullOrEmpty(attrName) && Util.isNotNullOrEmpty(attrValue)) {

        Filter valueFilter = Filter.eq("value", attrValue);
        Filter finalFilter = Filter.and(appFilter, attributeFilter, valueFilter);
        ManagedAttribute entitlement = context.getUniqueObject(ManagedAttribute.class, finalFilter);

        if (entitlement != null) {
        bundleSnowAssignmentGroup = findAssignmentFromBundle(entitlement, plan.getString("identityRequestId"), context);
        if (Util.isNotNullOrEmpty(bundleSnowAssignmentGroup)) {
        assignmentGroup = bundleSnowAssignmentGroup;
        } else {
        assignmentGroup = entitlement.getAttribute("snowAssignmentGroup");
        }
		if (Util.isNotNullOrEmpty(assignmentGroup)) {
		 if(reqName==null){        
		assignmentGroup="fe159ef11b935094768fea4fad4bcbe5";
		}
        businessApplication = entitlement.getAttribute("ascBusinessApplication");
        propertyMap = addPropertyInPlan(entitlement);
        AccountRequest eachAccountReq = new AccountRequest(request);
        if (Util.isNotNullOrEmpty(assignmentGroup)) {
		 if(reqName==null){        
		assignmentGroup="fe159ef11b935094768fea4fad4bcbe5";
		}
        eachAccountReq.add(new AttributeRequest("assignment_group", ProvisioningPlan.Operation.Set, assignmentGroup));
        }
        if (Util.isNotNullOrEmpty(businessApplication)) {
        eachAccountReq.add(new AttributeRequest("businessApplication", ProvisioningPlan.Operation.Set, businessApplication));
        }
        if (propertyMap != null && !propertyMap.isEmpty()) {
        propertyAttr = eachAccountReq.getArguments();
        if (null != propertyAttr && null != propertyAttr.getMap()) {
        accReqAttrMap = propertyAttr.getMap();
        }
        accReqAttrMap.put("ObjectProperties", propertyMap);
        if (propertyAttr == null) {
        propertyAttr = new Attributes();
        }
        propertyAttr.setMap(accReqAttrMap);
        eachAccountReq.setArguments(propertyAttr);
        }
        isAccReqAdded = true;
        splitAccountRequests.add(eachAccountReq);
        }
        if (entitlement != null) {
        //context.decache(entitlement);
        }
        } else if (attrValue instanceof List && Util.isNotNullOrEmpty(attrName) && null != attrValue) {

        Filter valueFilter = Filter.in("value", attrValue);
        Filter finalFilter = Filter.and(appFilter, attributeFilter, valueFilter);
        QueryOptions qo = new QueryOptions();
        qo.add(finalFilter);
        List entitlementList = context.getObjects(ManagedAttribute.class, qo);
        if (entitlementList != null && !entitlementList.isEmpty()) {
        for (ManagedAttribute eachEntitlement: entitlementList) {
        AttributeRequest eachAttributeReq = new AttributeRequest(attrName, attrRequest.getOp(), eachEntitlement.getValue());
        AccountRequest eachAccountReq = new AccountRequest(request);
        eachAccountReq.remove(attrRequest);

        eachAccountReq.add(eachAttributeReq);
        bundleSnowAssignmentGroup = findAssignmentFromBundle(eachEntitlement, plan.getString("identityRequestId"), context);
        if (Util.isNotNullOrEmpty(bundleSnowAssignmentGroup)) {
        assignmentGroup = bundleSnowAssignmentGroup;
        } else {
        assignmentGroup = eachEntitlement.getAttribute("snowAssignmentGroup");
        }
		if (Util.isNotNullOrEmpty(assignmentGroup)) {
		 if(reqName==null){        
		assignmentGroup="fe159ef11b935094768fea4fad4bcbe5";
		}
        businessApplication = eachEntitlement.getAttribute("ascBusinessApplication");
        propertyMap = addPropertyInPlan(eachEntitlement);
        if (Util.isNotNullOrEmpty(assignmentGroup)) {
		if(reqName==null){        
		assignmentGroup="fe159ef11b935094768fea4fad4bcbe5";
		}
        eachAccountReq.add(new AttributeRequest("assignment_group", ProvisioningPlan.Operation.Set, assignmentGroup));
        }
        if (Util.isNotNullOrEmpty(businessApplication)) {
        eachAccountReq.add(new AttributeRequest("businessApplication", ProvisioningPlan.Operation.Set, businessApplication));
        }
        if (propertyMap != null && !propertyMap.isEmpty()) {
        propertyAttr = eachAccountReq.getArguments();
        if (null != propertyAttr && null != propertyAttr.getMap()) {
        accReqAttrMap = propertyAttr.getMap();
        }
        accReqAttrMap.put("ObjectProperties", propertyMap);
        if (propertyAttr == null) {
        propertyAttr = new Attributes();
        }
        propertyAttr.setMap(accReqAttrMap);
        eachAccountReq.setArguments(propertyAttr);
        }
        isAccReqAdded = true;
        splitAccountRequests.add(eachAccountReq);
        }
        }
        }
        }
        }

        /*enable or disable case or account req doesnot have attreq or account req doesnot have entitlement */
        if (Util.isEmpty(attributeRequests) || !isAccReqAdded) {

        AccountRequest eachAcctReq = new AccountRequest(request);

        String appName = request.getApplication();
        Application appObj = context.getObjectByName(Application.class, appName);
        if (appObj != null) {
        assignmentGroup = (String)((appObj.getAttributeValue("snowAssignmentGroup") != null) ? appObj.getAttributeValue("snowAssignmentGroup") : "");

        businessApplication = (String)((appObj.getAttributeValue("ascBusinessApplication") != null) ? appObj.getAttributeValue("ascBusinessApplication") : appName);
		if (Util.isNotNullOrEmpty(assignmentGroup)) {
		 if(reqName==null){        
		assignmentGroup="fe159ef11b935094768fea4fad4bcbe5";
		}
        if (Util.isNotNullOrEmpty(assignmentGroup)) {
		if(reqName==null){        
		assignmentGroup="fe159ef11b935094768fea4fad4bcbe5";
		}
        eachAcctReq.add(new AttributeRequest("assignment_group", ProvisioningPlan.Operation.Set, assignmentGroup));
        }
        if (Util.isNotNullOrEmpty(businessApplication)) {
        eachAcctReq.add(new AttributeRequest("businessApplication", ProvisioningPlan.Operation.Set, businessApplication));
        }
        //context.decache(appObj);
        }
        isAccReqAdded = true;
        splitAccountRequests.add(eachAcctReq);
        }

        }
        }
        plan.setAccountRequests(splitAccountRequests);
        }
        logger.debug("Exiting addAssignmentGroupInPlan");
        }
        }
        }
        }
