        public String buildFullName(Identity identity) {

        String firstName = identity.getFirstname();
        String lastName = identity.getLastname();
        String middleName = identity.getStringAttribute("middleName");
        String fullName = firstName;
        if (middleName != null) {
        fullName = fullName + " " + middleName;
        }
        fullName = fullName + " " + lastName;

        return fullName;
        }

        public String getAttributeRequest(SailPointContext context, AccountRequest accountReq, String attrName) {
        String result = null;

        AttributeRequest attrReq = accountReq.getAttributeRequest(attrName);
        if (attrReq != null) {
        if (attrReq.getValue() instanceof String) {
        return attrReq.getValue();
        }
        }
        if (result == null) {
        result = "N/A";
        }
        return result;
        }
        public List getRoleAttributeRequests(SailPointContext context, AccountRequest accountReq, String attrName) {
        List results = new ArrayList();

        List attrReqList = accountReq.getAttributeRequests(attrName);
        if (attrReqList != null && attrReqList.size()> 0) {
        for (AttributeRequest attrReq: attrReqList) {
        results.add(attrReq.getValue());
        }
        }
        if (results.size()> 0) {
        results.add("N/A");
        }
        return results;
        }
        public List getAttributeRequestList(SailPointContext context, AccountRequest accountReq, String attrName) {
        List result = new ArrayList();
        AttributeRequest attrReq = accountReq.getAttributeRequest(attrName);
        if (attrReq != null) {

        if (attrReq.getValue() instanceof List) {

        result.addAll((List) attrReq.getValue());
        } else if (attrReq.getValue() instanceof String) {

        result.add((String) attrReq.getValue());
        }
        }
        return result;
        }

        public String newUpdateRequirement(SailPointContext context, ProvisioningPlan plan, String comment, Identity identity, Map arguments) {
        Map map = new HashMap();
        if (comment != null) {
        comment += "\n\n";
        }
        try {
        if (plan != null && identity != null) {
		String strManager=null;
        String managerEmail=null;
        String managerPhoneNumber=null;
        if(identity.getManager()!=null){

        strManager=identity.getManager().getName()+"-"+identity.getManager().getDisplayableName();
        managerEmail=(identity.getManager().getEmail()==null) ? "N/A" :identity.getManager().getEmail();     
        managerPhoneNumber=(identity.getManager().getAttribute("telephoneNumber")==null) ? "N/A":identity.getManager().getAttribute("telephoneNumber");
        }
        List accountRequests = plan.getAccountRequests();
        if (!Util.isEmpty(accountRequests)) {
        for (AccountRequest account: accountRequests) {
        applicationName = account.getApplicationName();
        if ("SCI".equalsIgnoreCase(applicationName)) {
        if (comment == null) {
        comment = "Request  Information:\n";
        }
        //comment+="\n\nUser Full Name: "+buildFullName(identity)+"\n";
        comment += "\n\nRequested for: " + identity.getDisplayableName() + "\n";
        comment += "User facility name: " + identity.getAttribute("buildingId") + "\n";
        comment += "User department: " + identity.getAttribute("department") + "\n";
        comment += "User phone number: " + identity.getAttribute("telephoneNumber") + "\n\n\n\n";
        comment += "User Email: " + identity.getAttribute("email") + "\n";
		comment += "User Ministry: " + identity.getAttribute("ministry") + "\n";
        comment += "Manager: " + strManager + "\n";
        comment += "Manager Email: " + managerEmail + "\n";
        comment += "Manager Phone Number: " + managerPhoneNumber + "\n";
        comment += "Application Name: " + applicationName + "\n\n";

        //comment+="\n\nRequested for: "+arguments.get("requestedFor")+"\n";
        comment += " Requested By First Name:  " + arguments.get("requestedByFirstName") + "\n";
        comment += "Requested By Last Name: " + arguments.get("requestedByLastName") + "\n";
        comment += "Network ID: " + arguments.get("networkID") + "\n\n";
        //comment += "Requested by: " + arguments.get("managerSamAccountName") + "\n\n\n\n";
		comment += "Requested By: " + arguments.get("opened_by") + "\n\n\n\n";


        comment += "Access Needed: " + "\n";
        comment += "---------------------\n";
        comment += " Access Type: " + getAttributeRequest(context, account, "accessType") + "\n\n";
        List faciltyAccList = getAttributeRequestList(context, account, "facilityAccess");
        comment += "Facility Access: " + "\n";
        if (faciltyAccList.size()> 0) {
        for (String fAccVal: faciltyAccList) {
        comment += fAccVal + "\n\n";
        }
        } else {
        comment += "N/A" + "\n\n";
        }
        List roleRequestList = getRoleAttributeRequests(context, account, "Role");
        comment += "Application Entitlements: " + "\n---------------------\n";
        if (roleRequestList.size()> 0) {
        for (String entValue: roleRequestList) {
        comment += entValue + "\n\n";
        }
        } else {
        comment += "N/A" + "\n\n";
        }
        } else if ("Order Facilitator".equalsIgnoreCase(applicationName)) {
        if (comment == null){
        comment = "Request Information:\n-----------------------------";
        }
        else{
        comment += "Request Information:\n-----------------------------";
        }	

        comment += "\n\nRequested for: " + identity.getDisplayableName() + "\n";
        //comment+="\n\nUser Full Name: "+buildFullName(identity)+"\n";
        comment += "User facility name: " + identity.getAttribute("buildingId") + "\n";
        comment += "User department: " + identity.getAttribute("department") + "\n";
        comment += "User phone number: " + identity.getAttribute("telephoneNumber") + "\n\n\n\n";
        comment += "User Email: " + identity.getAttribute("email") + "\n";
		comment += "User Ministry: " + identity.getAttribute("ministry") + "\n";
        comment += "Manager: " + strManager + "\n";
        comment += "Manager Email: " + managerEmail + "\n";
        comment += "Manager Phone Number: " + managerPhoneNumber + "\n";
        comment += "Application Name: " + applicationName + "\n\n";

        //comment+="\n\nRequested for: "+arguments.get("requestedFor")+"\n";
        comment += " Requested By First Name:  " + arguments.get("requestedByFirstName") + "\n";
        comment += "Requested By Last Name: " + arguments.get("requestedByLastName") + "\n";
        comment += "Network ID: " + arguments.get("networkID") + "\n\n";
        //comment += "Requested by: " + arguments.get("managerSamAccountName") + "\n\n\n\n";
		comment += "Requested By: " + arguments.get("opened_by") + "\n\n\n\n";

        comment += "Access Needed: \n";
        comment += "---------------------\n";
        comment += " Access Type: " + getAttributeRequest(context, account, "accessType") + "\n\n";
        List faciltyAccList = getAttributeRequestList(context, account, "facilityAccess");
        comment += "Facility Access: \n";
        comment += "---------------------\n";
        if (faciltyAccList.size()> 0) {
        for (String fAccVal: faciltyAccList) {
        comment += fAccVal + "\n\n";
        }
        }
        List roleRequestList = getRoleAttributeRequests(context, account, "Role");
        comment += "Application Entitlements: \n";
        comment += "---------------------\n";
        if (roleRequestList.size()> 0) {
        for (String entValue: roleRequestList) {
        comment += entValue + "\n\n";
        }
        } else {
        comment += "N/A" + "\n\n";
        }
        } else {
        // Add User Information for all Non-SCI and OF apps for all operations
        if (comment == null)
        comment = "Request Information:\n-----------------------------";
        else
        comment += "Request Information:\n-----------------------------";

        comment += "\n\nRequested for: " + identity.getDisplayableName() + "\n";
        //comment+="\n\nRequested for: "+buildFullName(identity)+"\n";
        comment += " Requested By First Name:  " + arguments.get("requestedByFirstName") + "\n";
        comment += "Requested By Last Name: " + arguments.get("requestedByLastName") + "\n";
        //comment += "Requested By: " + arguments.get("managerSamAccountName") + "\n\n\n\n";      
		 comment += "Requested By: " + arguments.get("opened_by") + "\n\n\n\n";
        comment += "Network ID: " + arguments.get("networkID") + "\n\n";
        comment += "User Ministry: " + identity.getAttribute("ministry") + "\n";
        comment += "Manager: " + strManager + "\n";
        comment += "Manager Email: " + managerEmail + "\n";
        comment += "Manager Phone Number: " + managerPhoneNumber + "\n";
        comment += "Application details:\n-----------------------------\n";
        List getAttrRequests = account.getAttributeRequests();

        if (!account.getOperation().equals(AccountRequest.Operation.Create)) {
        //Application Account Name / Native Identity
        comment += "Account Username: " + account.getNativeIdentity() + "\n";
        //User Email Address
        String userEmail = "";
        userEmail = identity.getAttribute("email");
        comment += "User Email: " + userEmail + "\n";
        }
        for (AttributeRequest attrRequest: getAttrRequests) {
        comment += attrRequest.getOperation().toString() + "  " + attrRequest.getName() + " : " + attrRequest.getValue().toString() + "\n";
        }

        }
        }
        }
        } else {

        }
        } catch (Exception ex) {

        }
        return comment;
        }

