        public ProvisioningPlan newUpdateRequirementDesc(SailPointContext context, ProvisioningPlan plan, String comment, Identity identity, Map arguments) {
        // logs("Starting newUpdateRequirementDesct000001***" + comment, "snowdesk");
        Map map = new HashMap();
        if (comment != null) {
        comment += "\n\n";
        }
        try {
        if (plan != null @and identity != null) {
		 String strManager=null;
        String managerEmail=null;
        String managerPhoneNumber=null;
        if(identity.getManager()!=null){
         strManager=identity.getManager().getName()+"-"+identity.getManager().getDisplayableName();
        managerEmail=(identity.getManager().getEmail()==null) ? "N/A" :identity.getManager().getEmail();     
        managerPhoneNumber=(identity.getManager().getAttribute("telephoneNumber")==null) ? "N/A":identity.getManager().getAttribute("telephoneNumber");
        }
        List accountRequests = plan.getAccountRequests();
        if (!Util.isEmpty(accountRequests)) {
        for (AccountRequest account: accountRequests) {
        comment=null;
        applicationName = account.getApplicationName();
        //logs("newUpdateRequirement applicationName string :- " + applicationName, "snowdesk");
        if ("SCI".equalsIgnoreCase(applicationName)) {
        if (comment == null)
